import { useHeaderHeight } from '@react-navigation/elements'
import { useCallback, useEffect, useMemo, useState } from 'react'
import { View, useWindowDimensions } from 'react-native'
import { ActivityIndicator } from 'react-native-paper'
import { pdfjs, Document, Page } from 'react-pdf'
import { Scrollbar, Zoom, Mousewheel } from 'swiper/modules'
import type { SwiperClass } from 'swiper/react'
import { Swiper, SwiperSlide } from 'swiper/react'

import 'swiper/css'
import 'swiper/css/zoom'
import 'swiper/css/scrollbar'
import './CatalogueViewerSwiper.web.css'
import type { CatalogueViewerProps } from './types'
import { useAppSelector } from '../../redux'
import { useStyles } from '../../utils/useStyles'

if (!process.env.EXPO_PUBLIC_PDFJS_WORKER_URL) {
  throw new Error('missing pdfjs worker url')
}

pdfjs.GlobalWorkerOptions.workerSrc = new URL(process.env.EXPO_PUBLIC_PDFJS_WORKER_URL).toString()

export type CatalogueViewerSwiperProps = CatalogueViewerProps

export const CatalogueViewerSwiper = ({
  uri,
  horizontal,
  page,
  onPageChanged,
}: CatalogueViewerSwiperProps) => {
  const headerHeight = useHeaderHeight()
  const { width: windowWidth, height: windowHeight } = useWindowDimensions()
  const [numPages, setNumPages] = useState<number>()
  const [pageWidth, setPageWidth] = useState(0)
  const [pageHeight, setPageHeight] = useState(0)
  const [pdfLoaded, setPdfLoaded] = useState(false)
  const [swiper, setSwiper] = useState<SwiperClass | null>(null)
  const theme = useAppSelector((state) => state.ui.theme)

  const styles = useStyles(
    () => ({
      main: {
        height: windowHeight - headerHeight,
        justifyContent: 'center',
      },
      swiper: {
        width: '100%',
        height: '100%',
      },
      loader: {
        position: 'absolute',
        top: '50%',
        left: '50%',
        transform: 'translate(-50%, -50%)',
      },
    }),
    [windowHeight, headerHeight],
  )

  const handleOnDocumentLoadSuccess = useCallback(({ numPages }: { numPages: number }) => {
    setNumPages(numPages)
  }, [])

  const fitHorizontal = useMemo(() => {
    // thanks to: https://github.com/wojtekmaj/react-pdf/issues/718
    const wRatio = pageWidth / windowWidth
    const hRatio = pageHeight / windowHeight
    if (wRatio < hRatio) {
      return false
    }
    return true
  }, [pageHeight, pageWidth, windowWidth, windowHeight])

  const handleOnSwiper = useCallback((swiper: SwiperClass) => {
    setSwiper(swiper)
  }, [])

  const handleOnPageLoadSuccess = useCallback(
    ({ width, height }: { width: number; height: number }) => {
      setPageWidth(width)
      setPageHeight(height)
    },
    [],
  )

  const handleOnPageRenderSuccess = useCallback(
    (index: number) => {
      if (swiper && index === swiper.realIndex) {
        setPdfLoaded(true)
        onPageChanged(swiper.realIndex + 1, swiper.slides.length)
      }
    },
    [swiper, onPageChanged],
  )

  const handleOnSlideChange = useCallback(
    (swiper: SwiperClass) => {
      onPageChanged(swiper.realIndex + 1, swiper.slides.length)
    },
    [onPageChanged],
  )

  useEffect(() => {
    if (swiper) {
      swiper.changeDirection(horizontal ? 'horizontal' : 'vertical')
    }
  }, [horizontal, swiper])

  return (
    <View style={styles.main}>
      {!pdfLoaded && <ActivityIndicator style={styles.loader} size="large" />}
      <Document
        className="document"
        file={uri}
        onLoadSuccess={handleOnDocumentLoadSuccess}
        // TODO: handle errors
        onLoadError={(error) => {
          console.error(error)
        }}
      >
        <Swiper
          slidesPerView={1}
          modules={[Scrollbar, Zoom, Mousewheel]}
          onSwiper={handleOnSwiper}
          onSlideChange={handleOnSlideChange}
          initialSlide={page - 1}
          style={styles.swiper}
          pagination={{
            clickable: true,
          }}
          autoHeight
          zoom
          scrollbar
          mousewheel
        >
          {Array.from(new Array(numPages), (el, index) => (
            <SwiperSlide key={`page_${index + 1}`}>
              <div className="swiper-zoom-container">
                <Page
                  onRenderSuccess={() => handleOnPageRenderSuccess(index)}
                  pageNumber={index + 1}
                  renderAnnotationLayer={false}
                  renderTextLayer={false}
                  width={fitHorizontal ? windowWidth : undefined}
                  height={!fitHorizontal ? windowHeight - headerHeight : undefined}
                  onLoadSuccess={handleOnPageLoadSuccess}
                  className={`canvas ${theme === 'dark' ? 'canvas-dark' : 'canvas-light'}`}
                />
              </div>
            </SwiperSlide>
          ))}
        </Swiper>
      </Document>
    </View>
  )
}

export default CatalogueViewerSwiper
